import { type SVGTextElementAttributes } from 'react';

import { boundaryLabel } from './RangeLegendBoundaryLabel.sty.js';
import { ORIENTATION } from '../../../../../constants.js';
import { charsFontWidth12pixelsSize500Map } from '../../../../text-ellipsis/chars-font-width-map.js';
import {
  calculateWidth,
  TEXT_HEIGHT,
} from '../../../../text-ellipsis/truncate-string.js';
import {
  DEFAULT_LABEL_FONT_COLOR,
  DEFAULT_LABEL_FONT_SIZE,
  LABEL_FONT_WEIGHT,
  LABEL_GAP,
} from '../../constants.js';
import { useOrientation } from '../../context/RangeLegendOrientationContext.js';
import { useRangeLegendHoveredMarkerId } from '../../hooks/store/selectors.js';
import type { LabelAlignment } from '../../types/range-legend.internal.js';
import { getHorizontalLabelPosition } from '../../utils/get-horizontal-label-position.js';
import { getVerticalLabelPosition } from '../../utils/get-vertical-label-position.js';

interface RangeLegendBoundaryLabelProps
  extends SVGTextElementAttributes<SVGTextElement> {
  alignment: LabelAlignment;
  endPosition: number;
  startPosition: number;
  text: string;
}

export const RangeLegendBoundaryLabel = (
  props: RangeLegendBoundaryLabelProps,
) => {
  const { alignment, endPosition, startPosition, text, ...textProps } = props;

  const { orientation } = useOrientation();
  const hoveredMarkerId = useRangeLegendHoveredMarkerId();

  const labelTextWidth = calculateWidth(text, charsFontWidth12pixelsSize500Map);
  const labelTextHeight = TEXT_HEIGHT;

  const isVertical = orientation === ORIENTATION.Vertical;

  const { x: labelX, y: labelY } = !isVertical
    ? getHorizontalLabelPosition(
        labelTextWidth,
        startPosition,
        endPosition,
        alignment,
      )
    : getVerticalLabelPosition(
        labelTextHeight,
        startPosition,
        endPosition,
        alignment,
      );

  const isMarkerShown = hoveredMarkerId !== null;

  return (
    <text
      x={labelX + (isVertical ? LABEL_GAP : 0)}
      y={labelY + (!isVertical ? LABEL_GAP : 0)}
      fontSize={DEFAULT_LABEL_FONT_SIZE}
      fontWeight={LABEL_FONT_WEIGHT}
      fill={DEFAULT_LABEL_FONT_COLOR}
      className={boundaryLabel({ isMarkerShown })}
      role="listitem"
      aria-label={`Boundary ${text}`}
      {...textProps}
    >
      {text}
    </text>
  );
};
